-- Add unique constraint on name if not exists
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'funding_opportunities_name_unique') THEN
    ALTER TABLE funding_opportunities ADD CONSTRAINT funding_opportunities_name_unique UNIQUE (name);
  END IF;
END $$;

