-- Log import results
DO $$
DECLARE vc_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO vc_count FROM funding_opportunities WHERE opportunity_type IN ('vc', 'angel');
  RAISE NOTICE 'Total VC/Angel opportunities: %', vc_count;
END $$;